function out = fReadPftH5(fNam)%% function read PFT H5 file%% out = fReadPftH5(fNam)%%% Written by Kei Nakamura% % 2018/11/1: created%%% main body%h5disp(fNam1); % to see file infoout.info = h5info(fNam);out.dsc = h5read(fNam,'/description');out.pft = h5read(fNam,'/laser_pft');out.lsrZ = h5read(fNam,'/laser_z');out.lsrX = h5read(fNam,'/laser_x');out.wdt = h5read(fNam,'/laser_width');
